-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for athletic development.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('sprint-to-stick-deceleration', 'This drill isolates the braking component of multidirectional speed. Effective deceleration requires coordinated ankle, knee, and hip flexion to absorb force, with the athlete using body position to manage momentum before stopping or redirecting. McBurnie et al. highlight high-intensity decelerations as frequent team-sport demands that commonly precede a change of direction, stop, or re-acceleration.', 'Belongs in linear_deceleration (351) — foundational Output deceleration entry before aggressive COD or shuttle work.', 'Foundational Output deceleration drill before COD, shuttle turns, or reactive agility; after landing prep and snap-down stick work.', 'Deceleration and COD Output belong while the athlete is fresh — powerful braking, intentional plants, clean re-acceleration, low reps, generous rest. COD Output should look like powerful braking and clean re-acceleration, not tired shuttle running. Do not use short rest, repeated shuttles, or high volume when plant quality drops. Do not progress to COD if the athlete cannot stick a linear stop. Stop when braking contacts get loud or extra stutter steps appear.', 'Regress to jog-to-stick or fast walk-to-stick; progress to higher approach speed and shorter stop zone when freeze is clean for 2 seconds. Hypermobility athletes need active knee/ankle/hip control — no passive collapse.'),
  ('5-yard-accel-to-decel-stick', 'This drill combines a short acceleration with an immediate stop. That makes it a useful bridge between pure acceleration and COD because the athlete must produce speed, then absorb momentum. Deceleration is a key component before stopping, changing direction, or re-accelerating in sport.', 'Belongs in linear_deceleration (351) — acceleration-to-braking bridge after sprint-to-stick, before shuttle or cut progressions.', 'After basic Sprint to Stick when linear braking is clean; bridges pure acceleration Output with deceleration and early COD prep.', 'Deceleration and COD Output belong while the athlete is fresh — powerful braking, intentional plants, clean re-acceleration, low reps, generous rest. COD Output should look like powerful braking and clean re-acceleration, not tired shuttle running. Do not use short rest, repeated shuttles, or high volume when plant quality drops. If repeated with short rest it becomes conditioning. Stop when extra stutter steps or running through the stop zone appears.', 'Regress to jog 5 yards to stick; use larger stop zone and lower speed for beginners. Emphasize active braking — no knee collapse.'),
  ('lateral-bound-to-decel-stick', 'Lateral bounds train the athlete to project and absorb force in the frontal plane. The Prehab Guys cue landing softly, letting the hips and knees bend enough to absorb force, keeping the knees aligned over the toes, and avoiding inward knee collapse.', 'Belongs in lateral_deceleration (352) — frontal-plane braking bridge after jump-power lateral bound to stick.', 'After Lateral Bound to Stick (jump power) is clean; frontal-plane COD bridge before hard lateral cuts or reactive lateral agility.', 'Deceleration and COD Output belong while the athlete is fresh — powerful braking, intentional plants, clean re-acceleration, low reps, generous rest. COD Output should look like powerful braking and clean re-acceleration, not tired shuttle running. Do not use short rest, repeated shuttles, or high volume when plant quality drops. Do not progress to hard lateral cuts if landing is unstable or knee valgus appears. Regress to lateral line hops or supported balance.', 'Regress to lateral step to single-leg balance; use shorter distance and target landing zone. Prioritize knee/ankle alignment over bound distance.'),
  ('pro-agility-5-10-5-technical-rep', 'The 5-10-5, also called the pro-agility shuttle, includes rapid directional changes in a linear plane with three cones spaced 5 yards apart. It requires acceleration, deceleration, direction change, and re-acceleration. Science for Sport notes the Pro-Agility 5-10-5 is better treated as change-of-direction speed rather than true reactive agility because it is pre-planned.', 'Belongs in cod_power (353) — structured pre-planned COD rep after linear deceleration competency; not reactive agility without external cue.', 'After linear deceleration sticks are clean; technical COD rep with full rest — not a conditioning shuttle.', 'Deceleration and COD Output belong while the athlete is fresh — powerful braking, intentional plants, clean re-acceleration, low reps, generous rest. COD Output should look like powerful braking and clean re-acceleration, not tired shuttle running. Do not use short rest, repeated shuttles, or high volume when plant quality drops. Short rest turns this into Fitness / Repeatability. Do not label as reactive agility without an external cue.', 'Regress to 3-6-3 or walk-through version; use half-speed plant practice before max rep. Require plant alignment and trunk control.'),
  ('90-degree-cut-drill', 'A 90-degree cut requires the athlete to brake enough to redirect the center of mass, plant effectively, turn the hips/trunk, and accelerate in a new direction. COD biomechanics change with cut angle and approach velocity — faster approaches can compromise execution in the angle-velocity trade-off described by Dos''Santos et al.', 'Belongs in cod_power (353) — angled redirection after linear decel stick; approach speed and cut angle determine intensity.', 'After athletes can decelerate and stick; before 180-degree turns or reactive cuts when plant quality is clean.', 'Deceleration and COD Output belong while the athlete is fresh — powerful braking, intentional plants, clean re-acceleration, low reps, generous rest. COD Output should look like powerful braking and clean re-acceleration, not tired shuttle running. Do not use short rest, repeated shuttles, or high volume when plant quality drops. Progress only one variable at a time — approach speed or cut angle, not both. Do not use if linear deceleration is poor.', 'Regress to walk/jog 90-degree turn or controlled plant rehearsal; use plant-zone markers and slower approach for beginners.'),
  ('180-degree-turn-shuttle-cut', 'A 180-degree shuttle turn requires the athlete to decelerate strongly, rotate/reorient, and re-accelerate in the opposite direction. Strength Coach Curriculums breaks the 180-degree turn into approach, entry, and exit phases: approach speed, maximal deceleration while rotation begins, and maximal re-acceleration into the new direction.', 'Belongs in cod_power (353) — highest COD braking demand in cluster; approach speed must be carefully progressed.', 'After linear deceleration and lower-speed 180-degree mechanics are clean; highest braking demand in this cluster.', 'Deceleration and COD Output belong while the athlete is fresh — powerful braking, intentional plants, clean re-acceleration, low reps, generous rest. COD Output should look like powerful braking and clean re-acceleration, not tired shuttle running. Do not use short rest, repeated shuttles, or high volume when plant quality drops. Beginners should use lower-speed shuttle turn or decel stick first. Do not round every turn or chase speed over plant quality.', 'Regress to walk/jog shuttle with large turn radius or stick-turn before re-accelerating; strict plant alignment and reduced approach speed for hypermobility.'),
  ('curved-run-to-cut', 'Curved deceleration and curved sprinting are distinct from straight-line sprinting and stopping. Sportsmith notes that curved deceleration is a distinct challenge because many field tests isolate linear deceleration, while sport often requires braking and redirecting from curved paths.', 'Belongs in curved_to_cut (354) — curvilinear approach plus cut; start with curved sprint control before hard redirection.', 'After curved sprint control and 90-degree cut competency; for field/court athletes redirecting from curved approach paths.', 'Deceleration and COD Output belong while the athlete is fresh — powerful braking, intentional plants, clean re-acceleration, low reps, generous rest. COD Output should look like powerful braking and clean re-acceleration, not tired shuttle running. Do not use short rest, repeated shuttles, or high volume when plant quality drops. Curve radius too tight or surface slipping means regress. Athlete must run the curve before adding hard cut.', 'Regress to curved jog to direction change; use large-radius curve and controlled exit. Watch inside-leg knee/ankle alignment.')
) AS v(slug, why_works, why_here, best_placement, misuse, scale_guidance)
JOIN coaching.exercise e ON e.slug = v.slug
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_works = EXCLUDED.why_it_works,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();

-- Deceleration / COD cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'output_decel_cod_readiness',
  NULL,
  'Deceleration / COD Power without pre-fatigue',
  'COD Output requires fresh athletes, clean plants, generous rest, and controlled braking — not tired shuttle running.',
  'Output deceleration and COD cards express linear braking, lateral deceleration, plant-and-turn power, angled cuts, shuttle turns, and curved-to-cut redirection.',
  'High-intensity decelerations and cuts load ankles, knees, hips, and trunk under approach speed and cut angle. Poor placement, short rest, or progression before linear braking raises injury risk and trains poor plants.',
  'Master Sprint to Stick before COD power, use 2+ minute rest on 5-10-5 technical reps, progress approach speed or cut angle one variable at a time, and stop when plant quality drops.',
  'Do not program COD after conditioning, with shuttle-style short rest, or before linear deceleration competency — regress dose or change phase intent.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
